diff --git a/packages/svelte/src/compiler/phases/2-analyze/visitors/SnippetBlock.js b/packages/svelte/src/compiler/phases/2-analyze/visitors/SnippetBlock.js
index 7930c2b1a..747451050 100644
--- a/packages/svelte/src/compiler/phases/2-analyze/visitors/SnippetBlock.js
+++ b/packages/svelte/src/compiler/phases/2-analyze/visitors/SnippetBlock.js
@@ -11,6 +11,27 @@ import * as e from '../../../errors.js';
 export function SnippetBlock(node, context) {
 	context.state.analysis.snippets.add(node);

+	// In `experimental.async` mode, `{@render foo(await bar)}` is lowered to `$.async(...)`.
+	// Awaited arguments are forwarded to the snippet invocation via generated `$$argN` parameters.
+	// If the snippet doesn't declare enough parameters, any referenced identifiers may be undefined.
+	if (context.state.options.experimental.async) {
+		let max = node.parameters.length;
+
+		for (const renderer of node.metadata.renderers) {
+			const awaited = renderer.metadata.arguments.reduce((n, meta) => n + (meta.has_await ? 1 : 0), 0);
+			if (awaited > max) max = awaited;
+		}
+
+		for (let i = node.parameters.length; i < max; i++) {
+			node.parameters.push({
+				type: 'Identifier',
+				name: `$$arg${i}`,
+				start: node.start,
+				end: node.start
+			});
+		}
+	}
+
 	validate_block_not_empty(node.body, context);

 	if (context.state.analysis.runes) {
diff --git a/packages/svelte/src/compiler/phases/3-transform/client/visitors/RenderTag.js b/packages/svelte/src/compiler/phases/3-transform/client/visitors/RenderTag.js
index b7a6e6555..b2bb8ff6e 100644
--- a/packages/svelte/src/compiler/phases/3-transform/client/visitors/RenderTag.js
+++ b/packages/svelte/src/compiler/phases/3-transform/client/visitors/RenderTag.js
@@ -71,15 +71,37 @@ export function RenderTag(node, context) {
 	}

 	const async_values = memoizer.async_values();
+	const async_ids = memoizer.async_ids();

 	if (async_values) {
+		const boundary_node = context.state.node;
+
+		// If we're in async mode, render statements are executed inside `$.async(...)`,
+		// and any awaited arguments are passed as extra parameters to that callback.
+		//
+		// For static snippet calls (i.e. not `$.snippet(...)`), we must forward those
+		// extra parameters to the snippet invocation, otherwise the snippet's generated
+		// `$$argN` parameters won't get values, leading to `ReferenceError`s when
+		// the snippet body references them.
+		for (const stmt of statements) {
+			if (
+				stmt.type === 'ExpressionStatement' &&
+				stmt.expression.type === 'CallExpression' &&
+				stmt.expression.arguments[0] === boundary_node
+			) {
+				stmt.expression.arguments.push(
+					...async_ids.map((id) => b.thunk(b.call('$.get', id)))
+				);
+			}
+		}
+
 		context.state.init.push(
 			b.stmt(
 				b.call(
 					'$.async',
-					context.state.node,
-					memoizer.async_values(),
-					b.arrow([context.state.node, ...memoizer.async_ids()], b.block(statements))
+					boundary_node,
+					async_values,
+					b.arrow([boundary_node, ...async_ids], b.block(statements))
 				)
 			)
 		);
