    41→	let resolve = (value) => {};
    42→
    43→	/** @param {any} [reason] */
    44→	let reject = (reason) => {};
    45→
    46→	/** @type {Promise<any>} */
    47→	const promise = new Promise((f, r) => {
    48→		resolve = f;
    49→		reject = r;
    50→	});
