   216→			const split = log.split('%c');
   217→
   218→			const first = /** @type {string} */ (split.shift()).trim();
   219→			if (first) normalised.push({ log: first });
   220→
   221→			while (split.length > 0) {
   222→				const log = /** @type {string} */ (split.shift()).trim();
   223→				const highlighted = logs.shift() === 'color: CornflowerBlue; font-weight: bold';
   224→
