     1→/** @import { Effect, Source, TemplateNode, } from '#client' */
     2→import {
     3→	BOUNDARY_EFFECT,
     4→	EFFECT_PRESERVED,
     5→	EFFECT_RAN,
     6→	EFFECT_TRANSPARENT
     7→} from '#client/constants';
     8→import { component_context, set_component_context } from '../../context.js';
     9→import { handle_error, invoke_error_boundary } from '../../error-handling.js';
    10→import { block, branch, destroy_effect, pause_effect } from '../../reactivity/effects.js';
    11→import {
    12→	active_effect,
    13→	active_reaction,
    14→	get,
    15→	set_active_effect,
    16→	set_active_reaction
    17→} from '../../runtime.js';
    18→import {
    19→	hydrate_next,
    20→	hydrate_node,
    21→	hydrating,
    22→	next,
    23→	remove_nodes,
    24→	set_hydrate_node
    25→} from '../hydration.js';
    26→import { get_next_sibling } from '../operations.js';
    27→import { queue_micro_task } from '../task.js';
    28→import * as e from '../../errors.js';
    29→import * as w from '../../warnings.js';
    30→import { DEV } from 'esm-env';
    31→import { Batch, effect_pending_updates } from '../../reactivity/batch.js';
    32→import { internal_set, source } from '../../reactivity/sources.js';
    33→import { tag } from '../../dev/tracing.js';
    34→import { createSubscriber } from '../../../../reactivity/create-subscriber.js';
    35→
    36→/**
    37→ * @typedef {{
    38→ * 	 onerror?: (error: unknown, reset: () => void) => void;
    39→ *   failed?: (anchor: Node, error: () => unknown, reset: () => () => void) => void;
    40→ *   pending?: (anchor: Node) => void;
    41→ * }} BoundaryProps
    42→ */
    43→
    44→var flags = EFFECT_TRANSPARENT | EFFECT_PRESERVED | BOUNDARY_EFFECT;
    45→
    46→/**
    47→ * @param {TemplateNode} node
    48→ * @param {BoundaryProps} props
    49→ * @param {((anchor: Node) => void)} children
    50→ * @returns {void}
    51→ */
    52→export function boundary(node, props, children) {
    53→	new Boundary(node, props, children);
    54→}
    55→
    56→export class Boundary {
    57→	pending = false;
    58→
    59→	/** @type {Boundary | null} */
    60→	parent;
    61→
    62→	/** @type {TemplateNode} */
    63→	#anchor;
    64→
    65→	/** @type {TemplateNode} */
    66→	#hydrate_open;
    67→
    68→	/** @type {BoundaryProps} */
    69→	#props;
    70→
    71→	/** @type {((anchor: Node) => void)} */
    72→	#children;
    73→
    74→	/** @type {Effect} */
    75→	#effect;
    76→
    77→	/** @type {Effect | null} */
    78→	#main_effect = null;
    79→
    80→	/** @type {Effect | null} */
    81→	#pending_effect = null;
    82→
    83→	/** @type {Effect | null} */
    84→	#failed_effect = null;
    85→
    86→	/** @type {DocumentFragment | null} */
    87→	#offscreen_fragment = null;
    88→
    89→	#pending_count = 0;
    90→	#is_creating_fallback = false;
    91→
    92→	/**
    93→	 * A source containing the number of pending async deriveds/expressions.
    94→	 * Only created if `$effect.pending()` is used inside the boundary,
    95→	 * otherwise updating the source results in needless `Batch.ensure()`
    96→	 * calls followed by no-op flushes
    97→	 * @type {Source<number> | null}
    98→	 */
    99→	#effect_pending = null;
   100→
   101→	#effect_pending_update = () => {
   102→		if (this.#effect_pending) {
   103→			internal_set(this.#effect_pending, this.#pending_count);
   104→		}
   105→	};
   106→
   107→	#effect_pending_subscriber = createSubscriber(() => {
   108→		this.#effect_pending = source(this.#pending_count);
   109→
   110→		if (DEV) {
   111→			tag(this.#effect_pending, '$effect.pending()');
   112→		}
   113→
   114→		return () => {
   115→			this.#effect_pending = null;
   116→		};
   117→	});
   118→
   119→	/**
   120→	 * @param {TemplateNode} node
   121→	 * @param {BoundaryProps} props
   122→	 * @param {((anchor: Node) => void)} children
   123→	 */
   124→	constructor(node, props, children) {
   125→		this.#anchor = node;
   126→		this.#props = props;
   127→		this.#children = children;
   128→
   129→		this.#hydrate_open = hydrate_node;
   130→
   131→		this.parent = /** @type {Effect} */ (active_effect).b;
   132→
   133→		this.pending = !!this.#props.pending;
   134→
   135→		this.#effect = block(() => {
   136→			/** @type {Effect} */ (active_effect).b = this;
   137→
   138→			if (hydrating) {
   139→				hydrate_next();
   140→			}
   141→
   142→			const pending = this.#props.pending;
   143→
   144→			if (hydrating && pending) {
   145→				this.#pending_effect = branch(() => pending(this.#anchor));
   146→
   147→				// future work: when we have some form of async SSR, we will
   148→				// need to use hydration boundary comments to report whether
   149→				// the pending or main block was rendered for a given
   150→				// boundary, and hydrate accordingly
   151→				Batch.enqueue(() => {
   152→					this.#main_effect = this.#run(() => {
   153→						Batch.ensure();
   154→						return branch(() => this.#children(this.#anchor));
   155→					});
   156→
   157→					if (this.#pending_count > 0) {
   158→						this.#show_pending_snippet();
   159→					} else {
   160→						pause_effect(/** @type {Effect} */ (this.#pending_effect), () => {
   161→							this.#pending_effect = null;
   162→						});
   163→
   164→						this.pending = false;
   165→					}
   166→				});
   167→			} else {
   168→				try {
   169→					this.#main_effect = branch(() => children(this.#anchor));
   170→				} catch (error) {
   171→					this.error(error);
   172→				}
   173→
   174→				if (this.#pending_count > 0) {
   175→					this.#show_pending_snippet();
   176→				} else {
   177→					this.pending = false;
   178→				}
   179→			}
   180→		}, flags);
   181→
   182→		if (hydrating) {
   183→			this.#anchor = hydrate_node;
   184→		}
   185→	}
   186→
   187→	has_pending_snippet() {
   188→		return !!this.#props.pending;
   189→	}
   190→
   191→	/**
   192→	 * @param {() => Effect | null} fn
   193→	 */
   194→	#run(fn) {
   195→		var previous_effect = active_effect;
   196→		var previous_reaction = active_reaction;
   197→		var previous_ctx = component_context;
   198→
   199→		set_active_effect(this.#effect);
   200→		set_active_reaction(this.#effect);
   201→		set_component_context(this.#effect.ctx);
   202→
   203→		try {
   204→			return fn();
   205→		} catch (e) {
   206→			handle_error(e);
   207→			return null;
   208→		} finally {
   209→			set_active_effect(previous_effect);
   210→			set_active_reaction(previous_reaction);
   211→			set_component_context(previous_ctx);
   212→		}
   213→	}
   214→
   215→	#show_pending_snippet() {
   216→		const pending = /** @type {(anchor: Node) => void} */ (this.#props.pending);
   217→
   218→		if (this.#main_effect !== null) {
   219→			this.#offscreen_fragment = document.createDocumentFragment();
   220→			move_effect(this.#main_effect, this.#offscreen_fragment);
   221→		}
   222→
   223→		if (this.#pending_effect === null) {
   224→			this.#pending_effect = branch(() => pending(this.#anchor));
   225→		}
   226→	}
   227→
   228→	/** @param {1 | -1} d */
   229→	#update_pending_count(d) {
